from flask import Flask, Response, request, g
from prometheus_client import Counter, Gauge, Histogram, generate_latest
from prometheus_client import CONTENT_TYPE_LATEST

app = Flask(__name__)

# Create some metrics
REQ_COUNT = Counter('request_count', 'App Request Count',
        ['app_name', 'method', 'endpoint', 'http_status', 'user_id', 'api_key'])
REQ_GAUGE = Gauge('request_in_progress', 'Requests in progress',
        ['app_name', 'endpoint', 'http_status', 'user_id', 'api_key'])
REQ_LATENCY = Histogram('request_latency_seconds', 'Request latency',
        ['app_name', 'endpoint'])

@app.before_request
def before_request():
    g.start_time = time.time()

@app.after_request
def after_request(response):
    if request.path == "/metrics":  # Don't count the /metrics request
        return response

    # Collect metrics
    req_latency = time.time() - g.start_time
    REQ_LATENCY.labels(app.name, request.path).observe(req_latency)
    REQ_COUNT.labels(app.name, request.method, request.path, 
                     response.status_code, request.headers.get('user_id', 'unknown'), 
                     request.headers.get('api_key', 'unknown')).inc()
    REQ_GAUGE.labels(app.name, request.path, 
                     response.status_code, request.headers.get('user_id', 'unknown'), 
                     request.headers.get('api_key', 'unknown')).dec()

    return response

@app.route('/')
def index():
    REQ_GAUGE.labels(app.name, request.path, 200, 
                     request.headers.get('user_id', 'unknown'), 
                     request.headers.get('api_key', 'unknown')).inc()
    return "Hello, World!"

@app.route('/metrics')
def metrics():
    return Response(generate_latest(), mimetype=CONTENT_TYPE_LATEST)

